@Service
public class ProdutoService {

    // unless = "#result == null": não cacheia resultado nulo — evita cachear
    // "não encontrado" e mascarar um produto criado depois
    @Cacheable(value = "produtos", key = "#id", unless = "#result == null")
    public Produto buscarPorId(Long id) {
        return produtoRepository.findById(id).orElse(null); // só bate no banco 1x
    }

    @CacheEvict(value = "produtos", key = "#produto.id")
    public Produto atualizar(Produto produto) {
        return produtoRepository.save(produto); // invalida cache na escrita
    }
}

// Fluxo típico de 2 camadas:
// Requisição -> Cache local (Caffeine) -> hit? retorna em ~microssegundos
//                     |
//                    miss
//                     v
//            Cache distribuído (Redis) -> hit? retorna em ~1-2ms
//                     |
//                    miss
//                     v
//               Banco de dados -> ~10-50ms+

