@Service
public class ProdutoService {

    // SEM unless: cacheia até resultado null — se o produto ainda não existe
    // quando a primeira chamada acontece, "null" fica cacheado, e o produto
    // criado alguns segundos depois continua "não encontrado" até o cache expirar
    @Cacheable(value = "produtos", key = "#id")
    public Produto buscarPorId(Long id) {
        return produtoRepository.findById(id).orElse(null);
    }

    public Produto atualizar(Produto produto) {
        // faltou @CacheEvict — o cache nunca é invalidado na escrita,
        // então buscarPorId() continua retornando o valor ANTIGO depois de um update
        return produtoRepository.save(produto);
    }
}

