public class NotificacaoService {

    @Async("notificacaoExecutor")
    public CompletableFuture<Void> enviarEmail(String destinatario, String conteudo) {
        emailClient.enviar(destinatario, conteudo); // operação lenta não bloqueia o request
        return CompletableFuture.completedFuture(null);
    }
